func employeeCount(employees []domain.Employee) string {
	total := len(employees)
	if total == 0 {
		return "No team members"
	}
	if total == 1 {
		return "1 team member"
	}
	return fmt.Sprintf("%d team members", total)
}

// maskAccount masks all but the last 4 digits of an account number.
func maskAccount(acct string) string {
	if len(acct) <= 4 {
		return acct
	}
	return "••••" + acct[len(acct)-4:]
}

// financialVal returns a field value from CompanyFinancials for pre-filling forms.
func financialVal(f *domain.CompanyFinancials, field string) string {
	if f == nil {
		return ""
	}
	switch field {
	case "bank_name":
		return f.BankName
	case "account_name":
		return f.AccountName
	case "bsb":
		return f.BSB
	case "account_number":
		return f.AccountNumber
	case "swift_code":
		return f.SwiftCode
	case "payment_provider":
		return f.PaymentProvider
	}
	return ""
}

// financialPrefixVal returns the invoice prefix, defaulting to "INV".
func financialPrefixVal(f *domain.CompanyFinancials) string {
	if f == nil || f.InvoicePrefix == "" {
		return "INV"
	}
	return f.InvoicePrefix
}

// financialCurrencyVal returns the invoice currency, defaulting to "AUD".
func financialCurrencyVal(f *domain.CompanyFinancials) string {
	if f == nil || f.InvoiceCurrency == "" {
		return "AUD"
	}
	return f.InvoiceCurrency
}

